&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;72-sctlscore_genes_cell_cycle&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#72-sctlscore_genes_cell_cycle&#34;&gt;#&lt;/a&gt; &lt;strong&gt;7.2  &lt;code&gt;sc.tl.score_genes_cell_cycle()&lt;/code&gt; &lt;/strong&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;计算细胞周期评分。&lt;/li&gt;
&lt;li&gt;示例：&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sc.tl.score_genes_cell_cycle(adata, s_genes=your_s_genes, g2m_genes=your_g2m_genes)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
